@staticmethod
def make_client(
    multiprocess_mode: bool,
    asyncio_mode: bool,
    vllm_config: VllmConfig,
    executor_class: type[Executor],
    log_stats: bool,
) -> "EngineCoreClient":
    # TODO: support this for debugging purposes.
    if asyncio_mode and not multiprocess_mode:
        raise NotImplementedError(
            "Running EngineCore in asyncio without multiprocessing "
            "is not currently supported."
        )

    if multiprocess_mode and asyncio_mode:
        return EngineCoreClient.make_async_mp_client(
            vllm_config, executor_class, log_stats
        )

    if multiprocess_mode and not asyncio_mode:
        return SyncMPClient(vllm_config, executor_class, log_stats)

    return InprocClient(vllm_config, executor_class, log_stats)

class InprocClient(EngineCoreClient):
    """
    InprocClient: client for in-process EngineCore. Intended
    for use in LLMEngine for V0-style add_request() and step()
        EngineCore setup in this process (no busy loop).

        * pushes EngineCoreRequest directly into the EngineCore
        * pulls EngineCoreOutputs by stepping the EngineCore
    """

    def __init__(self, *args, **kwargs):
        self.engine_core = EngineCore(*args, **kwargs)

    def get_output(self) -> EngineCoreOutputs:
        outputs, model_executed = self.engine_core.step_fn()
        self.engine_core.post_step(model_executed=model_executed)
        return outputs and outputs.get(0) or EngineCoreOutputs()

    def add_request(self, request: EngineCoreRequest) -> None:
        req, request_wave = self.engine_core.preprocess_add_request(request)
        self.engine_core.add_request(req, request_wave)

def _run_completion(
    self, prompts, params, output_type: type[_O], *,
    use_tqdm: bool | Callable[..., tqdm] = True,
    lora_request=None, priority=None,
    tokenization_kwargs=None, mm_processor_kwargs=None,
):
    self._add_completion_requests(
        prompts=prompts, params=params, use_tqdm=use_tqdm,
        lora_request=lora_request, priority=priority,
        tokenization_kwargs=tokenization_kwargs,
        mm_processor_kwargs=mm_processor_kwargs,
    )
    return self._run_engine(use_tqdm=use_tqdm, output_type=output_type)

def _render_and_add_requests(
    self, prompts, params, *, lora_requests=None, priorities=None,
) -> list[str]:
    added_request_ids: list[str] = []
    try:
        for i, prompt in enumerate(prompts):
            request_id = self._add_request(
                prompt, params[i],
                lora_request=self._resolve_mm_lora(
                    prompt,
                    None if lora_requests is None else lora_requests[i]),
                priority=0 if priorities is None else priorities[i],
            )
            added_request_ids.append(request_id)
    except Exception as e:
        if added_request_ids:
            self.llm_engine.abort_request(added_request_ids, internal=True)
        raise e
    return added_request_ids

def _add_request(
    self, prompt, params, lora_request=None, priority=0,
) -> str:
    if isinstance(params, SamplingParams):
        # We only care about the final output
        params.output_kind = RequestOutputKind.FINAL_ONLY
    request_id = str(next(self.request_counter))
    return self.llm_engine.add_request(
        request_id, prompt, params,
        lora_request=lora_request, priority=priority,
    )

def _run_engine(
    self, output_type, *, use_tqdm: bool | Callable[..., tqdm] = True,
) -> list[_O]:
    if use_tqdm:
        num_requests = self.llm_engine.get_num_unfinished_requests()
        tqdm_func = use_tqdm if callable(use_tqdm) else tqdm
        pbar = tqdm_func(
            total=num_requests, desc="Processed prompts",
            dynamic_ncols=True,
            postfix=(f"est. speed input: {0:.2f} toks/s, output: {0:.2f} toks/s"),
        )

    outputs: list[_O] = []
    total_in_toks = 0
    total_out_toks = 0
    while self.llm_engine.has_unfinished_requests():
        step_outputs = self.llm_engine.step()
        for output in step_outputs:
            assert isinstance(output, output_type)
            if output.finished:
                outputs.append(output)
                if use_tqdm:
                    if isinstance(output, RequestOutput):
                        n = len(output.outputs)
                        total_in_toks += len(output.prompt_token_ids) * n
                        in_spd = total_in_toks / pbar.format_dict["elapsed"]
                        total_out_toks += sum(
                            len(stp.token_ids) for stp in output.outputs)
                        out_spd = total_out_toks / pbar.format_dict["elapsed"]
                        pbar.postfix = (f"est. speed input: {in_spd:.2f} toks/s, "
                                        f"output: {out_spd:.2f} toks/s")
                        pbar.update(n)
                    else:
                        pbar.update(1)
                    if pbar.n == num_requests:
                        pbar.refresh()

    if use_tqdm:
        pbar.close()
    # Sort the outputs by request ID.
    return sorted(outputs, key=lambda x: int(x.request_id))
